function summarizeAUForgedOntology(payload = AU_FORGED_ONTOLOGY) {
  const personas = Array.isArray(payload?.personas) ? payload.personas : [];
  const phraseBank = Array.isArray(payload?.phraseBank) ? payload.phraseBank : [];
  const variationCount = personas.reduce((sum, persona) => sum + Number(persona?.variations?.length || 0), 0);
  return Object.freeze({
    schemaVersion: payload?.schemaVersion || 'td613.au_forged_ontology.v1',
    sourceModel: payload?.sourceModel || 'AU',
    auditStatus: payload?.auditStatus || 'unknown',
    phraseCount: phraseBank.length,
    personaCount: personas.length,
    variationCount
  });
}
// SOURCE: app/engine/generator-v2.js
function clamp01(value) {
  return Math.max(0, Math.min(1, Number(value || 0)));
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, Number(value || 0)));
}

function round(value, digits = 4) {
  return Number(Number(value || 0).toFixed(digits));
}

function normalizeText(text = '') {
  return String(text || '')
    .replace(/\r\n/g, '\n')
    .replace(/\u00A0/g, ' ')
    .replace(/\u2019/g, "'")
    .replace(/\u2018/g, "'")
    .replace(/\u2014/g, '-')
    .replace(/\u2013/g, '-')
    .trim();
}

function normalizeComparable(text = '') {
  return normalizeText(text)
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeMovementComparable(text = '') {
  return normalizeComparable(text)
    .replace(/\bi'm\b/g, 'i am')
    .replace(/\bi've\b/g, 'i have')
    .replace(/\bit's\b/g, 'it is')
    .replace(/\bthat's\b/g, 'that is')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function average(values = []) {
  const clean = (values || []).map((value) => Number(value || 0)).filter(Number.isFinite);
  return clean.length ? clean.reduce((sum, value) => sum + value, 0) / clean.length : 0;
}

function uniqueStrings(values = []) {
  return [...new Set((values || []).filter(Boolean))];
}

function escapeRegex(value = '') {
  return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

