  branchDynamics,
  routePressure,
  computeRoutePressure,
  fieldPotential,
  waveStats,
  custodyThreshold,
  criticalityIndex,
  providerDecision,
  HARBOR_LIBRARY,
  chooseHarbor,
  buildLedgerRow,
  computeReuseGain,
  estimateWitnessLoad,
  AU_FORGED_ONTOLOGY,
  summarizeAUForgedOntology,
  normalizeText,
  extractCadenceProfile,
  inferRegisterLaneFromText,
  compareTexts,
  buildCadenceTransfer,
  buildCadenceTransferLegacy,
  buildCadenceTransferTrace,
  buildCadenceTransferTraceLegacy,
  generateCadenceAuditMatrix,
  buildCadenceSignature,
  applyCadenceShell,
